import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function POST(
  req: NextRequest,
  props: { params: Promise<{ id: string }> }
) {
  try {
    const params = await props.params;
    const bookingId = params.id;

    if (!bookingId) {
      return NextResponse.json({ error: 'Missing booking ID' }, { status: 400 });
    }

    const result = await prisma.$transaction(async (tx) => {
      // Find booking first to ensure it's still PENDING
      const booking = await tx.booking.findUnique({
        where: { id: bookingId }
      });

      if (!booking) {
        throw new Error('NOT_FOUND');
      }

      if (booking.status !== 'PENDING') {
        throw new Error('INVALID_STATUS');
      }

      // Restore available spots on the trek
      await tx.trek.update({
        where: { id: booking.trekId },
        data: {
          availableSpots: { increment: booking.participants }
        }
      });

      // Mark the booking as CANCELLED
      const updatedBooking = await tx.booking.update({
        where: { id: bookingId },
        data: { status: 'CANCELLED' }
      });

      return updatedBooking;
    });

    return NextResponse.json({ success: true, booking: result });
  } catch (error: any) {
    if (error.message === 'NOT_FOUND') return NextResponse.json({ error: 'Not Found' }, { status: 404 });
    if (error.message === 'INVALID_STATUS') return NextResponse.json({ error: 'Booking is not pending' }, { status: 400 });
    
    console.error('Cancel Error:', error);
    return NextResponse.json({ error: 'Internal Error' }, { status: 500 });
  }
}
